1	export type Cell = [number, number];
2	
3	function isNeighbor(a: Cell, b: Cell): boolean {
4	  const isSameCell = a[0] === b[0] && a[1] === b[1];
5	  const isWithinOneStep =
6	    Math.abs(a[0] - b[0]) <= 1 && Math.abs(a[1] - b[1]) <= 1;
7	  return !isSameCell && isWithinOneStep;
8	}
9	
10	export function nextGeneration(liveCells: Cell[]): Cell[] {
11	  const countNeighbors = (cell: Cell): number =>
12	    liveCells.filter((other) => isNeighbor(other, cell)).length;
13	
14	  return liveCells.filter((cell) => {
15	    const neighbors = countNeighbors(cell);
16	    return neighbors === 2 || neighbors === 3;
17	  });
18	}
